    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchMyTrades
        //
        //     {
        //         "type": "BTC Sell order executed",
        //         "typeI": 6,
        //         "crypto": 5000,
        //         "amount": 35.4,
        //         "rate": 709800,
        //         "date": "2020-05-22T15:05:34.000Z",
        //         "unit": "INR",
        //         "factor": 100000000,
        //         "fee": 0.09,
        //         "delh_btc": -5000,
        //         "delh_inr": 0,
        //         "del_btc": 0,
        //         "del_inr": 35.4,
        //         "id": "2938823"
        //     }
        //
        // fetchTrades
        //
        //     {
        //         "tradeId":"1909151",
        //         "price":"61904.6300",
        //         "quote_volume":1618.05,
        //         "base_volume":0.02607254,
        //         "timestamp":1634548602000,
        //         "type":"buy"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        market = this.safeMarket(null, market);
        Object orderId = this.safeString2(trade, "id", "tradeId");
        Object timestamp = this.parse8601(this.safeString(trade, "date"));
        timestamp = this.safeInteger(trade, "timestamp", timestamp);
        Object priceString = this.safeString2(trade, "rate", "price");
        Object amountString = this.safeString(trade, "amount");
        Object side = this.safeStringLower(trade, "type");
        if (Helpers.isTrue(!Helpers.isEqual(side, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(side, "buy"), 0)))
            {
                side = "buy";
            } else if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(side, "sell"), 0)))
            {
                side = "sell";
            }
        }
        Object factor = this.safeString(trade, "factor");
        Object costString = null;
        if (Helpers.isTrue(!Helpers.isEqual(factor, null)))
        {
            amountString = Precise.stringDiv(amountString, factor);
        } else
        {
            amountString = this.safeString(trade, "base_volume");
            costString = this.safeString(trade, "quote_volume");
        }
        Object symbol = Helpers.GetValue(market, "symbol");
        Object fee = null;
        Object feeCostString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyCode = Helpers.GetValue(market, "quote");
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalTimestamp = timestamp;
        final Object finalSide = side;
        final Object finalAmountString = amountString;
        final Object finalCostString = costString;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", finalTimestamp );
            put( "datetime", BitbnsCore.this.iso8601(finalTimestamp) );
            put( "symbol", symbol );
            put( "id", orderId );
            put( "order", orderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", finalAmountString );
            put( "cost", finalCostString );
            put( "fee", finalFee );
        }}, market);
    }

