    public Object parseTransactionStatusByType(Object status, Object... optionalArgs)
    {
        Object type = Helpers.getArg(optionalArgs, 0, null);
        Object statusesByType = new java.util.HashMap<String, Object>() {{
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "0", "pending" );
                put( "1", "ok" );
            }} );
            put( "withdrawal", new java.util.HashMap<String, Object>() {{
                put( "0", "pending" );
                put( "1", "canceled" );
                put( "2", "pending" );
                put( "3", "failed" );
                put( "4", "pending" );
                put( "5", "failed" );
                put( "6", "ok" );
            }} );
        }};
        Object statuses = this.safeDict(statusesByType, type, new java.util.HashMap<String, Object>() {{}});
        return this.safeString(statuses, status, status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // fetchDeposits
        //
        //     {
        //         "type":"USDT deposited",
        //         "typeI":1,
        //         "amount":100,
        //         "date":"2021-04-24T14:56:04.000Z",
        //         "unit":"USDT",
        //         "factor":100,
        //         "fee":0,
        //         "delh_btc":0,
        //         "delh_inr":0,
        //         "rate":0,
        //         "del_btc":10000,
        //         "del_inr":0
        //     }
        //
        // fetchWithdrawals
        //
        //     ...
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(transaction, "unit");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.parse8601(this.safeString2(transaction, "date", "timestamp"));
        Object type = this.safeString(transaction, "type");
        Object expTime = this.safeString(transaction, "expTime", "");
        Object status = null;
        if (Helpers.isTrue(!Helpers.isEqual(type, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(type, "deposit"), 0)))
            {
                type = "deposit";
                status = "ok";
            } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(type, "withdraw"), 0)) || Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(expTime, "withdraw"), 0))))
            {
                type = "withdrawal";
            }
        }
        // const status = this.parseTransactionStatusByType (this.safeString (transaction, 'status'), type);
        Object amount = this.safeNumber(transaction, "amount");
        Object feeCost = this.safeNumber(transaction, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", finalFeeCost );
            }};
        }
        final Object finalType = type;
        final Object finalStatus = status;
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", null );
            put( "txid", null );
            put( "timestamp", timestamp );
            put( "datetime", BitbnsCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", null );
            put( "addressTo", null );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", finalType );
            put( "amount", amount );
            put( "currency", code );
            put( "status", finalStatus );
            put( "updated", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", finalFee );
        }};
    }

